import{_ as e,c as r,o as a,aN as o}from"./chunks/framework.CqA5BTDU.js";const u=JSON.parse('{"title":"容器基础","description":"","frontmatter":{},"headers":[],"relativePath":"09.容器化/01-容器基础.md","filePath":"09.容器化/01-容器基础.md","lastUpdated":null}'),d={name:"09.容器化/01-容器基础.md"};function n(c,t,i,s,p,l){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="容器基础" tabindex="-1">容器基础 <a class="header-anchor" href="#容器基础" aria-label="Permalink to &quot;容器基础&quot;">​</a></h1><p>Docker 做的事可以概括为一句话：把应用和它需要的所有东西打包在一起，让它在任何安装了 Docker 的机器上都能跑起来。</p><p>&quot;需要的所有东西&quot;包括了操作系统用户空间、运行时库、系统工具、配置文件、依赖包——不是只把二进制文件复制过去。一台机器上装的 libssl 版本和另一台不同、glibc 版本差了一代、Python 环境变量没设对——这些在传统部署里经常出现的问题，Docker 的思路是把这些差异封装进镜像，运行时不再依赖宿主机上装了什么。</p><h2 id="容器和虚拟机——共享内核还是独立系统" tabindex="-1">容器和虚拟机——共享内核还是独立系统 <a class="header-anchor" href="#容器和虚拟机——共享内核还是独立系统" aria-label="Permalink to &quot;容器和虚拟机——共享内核还是独立系统&quot;">​</a></h2><p>虚拟机用 hypervisor 在物理硬件上虚拟出一整套硬件，每台虚拟机有自己的操作系统内核。容器没有自己的内核，它和宿主机共享同一个内核，靠 Linux 的 namespace 和 cgroups 做隔离和资源限制。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20TD%0A%20%20%20%20subgraph%20vm%5B%22%E8%99%9A%E6%8B%9F%E6%9C%BA%22%5D%0A%20%20%20%20%20%20%20%20app_vm%5B%22%E5%BA%94%E7%94%A8%22%5D%0A%20%20%20%20%20%20%20%20libs_vm%5B%22%E4%BE%9D%E8%B5%96%E5%BA%93%22%5D%0A%20%20%20%20%20%20%20%20os_vm%5B%22%E5%AE%8C%E6%95%B4%E6%93%8D%E4%BD%9C%E7%B3%BB%E7%BB%9F%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20container%5B%22%E5%AE%B9%E5%99%A8%22%5D%0A%20%20%20%20%20%20%20%20app_ct%5B%22%E5%BA%94%E7%94%A8%22%5D%0A%20%20%20%20%20%20%20%20libs_ct%5B%22%E4%BE%9D%E8%B5%96%E5%BA%93%22%5D%0A%20%20%20%20end%0A%20%20%20%20infra_vm%5B%22Hypervisor%22%5D%0A%20%20%20%20infra_ct%5B%22Docker%20Engine%22%5D%0A%20%20%20%20os_shared%5B%22%E5%AE%BF%E4%B8%BB%E6%9C%BA%E6%93%8D%E4%BD%9C%E7%B3%BB%E7%BB%9F%22%5D%0A%20%20%20%20hw%5B%22%E7%89%A9%E7%90%86%E7%A1%AC%E4%BB%B6%22%5D%0A%0A%20%20%20%20app_vm%20--%3E%20libs_vm%20--%3E%20os_vm%20--%3E%20infra_vm%20--%3E%20hw%0A%20%20%20%20app_ct%20--%3E%20libs_ct%20--%3E%20infra_ct%20--%3E%20os_shared%20--%3E%20hw%0A"></div><p>因为共享内核，容器镜像不需要打包一个完整的操作系统——镜像可以很小（几十 MB），启动可以很快（秒级），一台物理机上可以跑的容器密度远超虚拟机。代价是隔离性不如虚拟机。内核漏洞可能被用来跨容器攻击，Linux namespace 隔离的是视角（进程看到什么、网络看到什么），不是把所有资源都物理隔开。对安全隔离有严格要求的场景（多租户、不受信代码执行），虚拟机仍然是更稳妥的选择。</p><h2 id="三个核心对象——镜像、容器、仓库" tabindex="-1">三个核心对象——镜像、容器、仓库 <a class="header-anchor" href="#三个核心对象——镜像、容器、仓库" aria-label="Permalink to &quot;三个核心对象——镜像、容器、仓库&quot;">​</a></h2><p>Docker 里反复出现三个对象，后面所有操作都在它们之间来回：</p><p><strong>镜像</strong>是只读的模板。它不是一个大文件，而是一叠文件系统层——基础系统一层，装软件一层，复制应用文件一层。每层只记录和上一层的差异，相同数据不重复存。镜像可以复制、分发，但不能修改。</p><p><strong>容器</strong>是镜像跑起来的实例。Docker 在镜像的只读层上面加了一层可写层，容器里所有的写操作（新建文件、修改配置、写日志）都发生在这层。删除容器时，这层可写层也一起消失——容器自己产生的数据，除非主动做了持久化，否则随着容器没了。</p><p><strong>仓库</strong>是存放和分发镜像的地方。Docker Hub 是最常见的公共仓库，公司内部通常部署 Harbor 或其他私有仓库。&quot;拉镜像&quot;就是从仓库把镜像下载到本地 Docker。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20registry%5B%22%E9%95%9C%E5%83%8F%E4%BB%93%E5%BA%93%22%5D%20--%20%22push%20%E4%B8%8A%E4%BC%A0%22%20--%3E%20local%5B%22%E6%9C%AC%E5%9C%B0%E9%95%9C%E5%83%8F%22%5D%0A%20%20%20%20registry%20--%20%22pull%20%E6%8B%89%E5%8F%96%22%20--%3E%20local%0A%20%20%20%20local%20--%20%22run%20%E8%BF%90%E8%A1%8C%22%20--%3E%20container%5B%22%E5%AE%B9%E5%99%A8%22%5D%0A%20%20%20%20container%20--%20%22commit%20%E4%BF%9D%E5%AD%98%22%20--%3E%20local%0A"></div><h2 id="docker-技术栈的分层" tabindex="-1">Docker 技术栈的分层 <a class="header-anchor" href="#docker-技术栈的分层" aria-label="Permalink to &quot;Docker 技术栈的分层&quot;">​</a></h2><p>平时敲的 <code>docker run</code> 背后并不只有 Docker 自己在干活：</p><table tabindex="0"><thead><tr><th>组件</th><th>位置</th><th>职责</th></tr></thead><tbody><tr><td>Docker CLI</td><td>命令行</td><td>接收 <code>docker run</code>、<code>docker pull</code> 等命令，发给 daemon</td></tr><tr><td>dockerd</td><td>宿主机守护进程</td><td>接收 API 请求，管理镜像、容器、网络、存储</td></tr><tr><td>containerd</td><td>dockerd 和 runc 之间</td><td>管理容器生命周期——拉镜像、创建容器、管理存储和网络</td></tr><tr><td>runc</td><td>最底层</td><td>按 OCI 规范实际创建和运行容器，容器启动后退出</td></tr></tbody></table><p>一条 <code>docker run</code> 背后的大致流程：CLI 发给 dockerd → dockerd 发给 containerd → containerd 启动 runc 创建容器 → 容器进程跑起来后 runc 退出。排查更底层的问题时才会直接接触 containerd 和 runc，日常运维主要面向 <code>docker</code> 命令。</p><h2 id="隔离依赖什么" tabindex="-1">隔离依赖什么 <a class="header-anchor" href="#隔离依赖什么" aria-label="Permalink to &quot;隔离依赖什么&quot;">​</a></h2><p>Docker 的隔离不是自己发明的，是对 Linux 内核能力的组合使用：</p><p><strong>namespace</strong> 让进程看到不同的系统视图。PID namespace 让容器里的进程看到自己是 PID 1，在宿主机上它只是一个普通进程号；Network namespace 让容器有自己的网卡、IP、路由表；Mount namespace 让容器有自己的文件系统挂载点；UTS namespace 让容器有自己的主机名。一台宿主机跑 50 个容器，每个都觉得自己是独立的小 Linux 系统——其实是 50 组 namespace 各自圈定了一块视野。</p><p><strong>cgroups</strong> 控制容器能用多少资源。CPU、内存、磁盘 IO 都可以限制。一台机器上跑了多个容器，其中一个 Java 应用吃了 8G 内存，如果不设限制，其他容器可能被挤出内存。cgroups 把&quot;这个容器最多用 2 核 CPU、1G 内存&quot;变成内核强制执行的硬上限。</p><p><strong>联合文件系统</strong>让镜像的分层成为可能。overlay2 是当前最常用的存储驱动，它把多个只读镜像层叠在一起，容器看到的是一个完整文件系统，实际物理存储上相同的文件只存一份。修改文件时会复制到可写层再改（copy-on-write），不影响镜像和其他共享同一层的容器。</p><p><strong>capabilities</strong> 把 root 的超级权限拆成细粒度能力。容器默认启动时，即使容器内显示 <code>root</code>，也只被授予了一部分 capabilities——不能加载内核模块、不能修改系统时间、不能直接访问硬件。需要特定能力时用 <code>--cap-add</code> 显式授予，而不是直接 <code>--privileged</code> 一把全开。</p><h2 id="容器的生命周期" tabindex="-1">容器的生命周期 <a class="header-anchor" href="#容器的生命周期" aria-label="Permalink to &quot;容器的生命周期&quot;">​</a></h2><p><code>docker run</code> 实际上是 <code>create</code> + <code>start</code> 的组合：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20created%5B%22created%20%E5%B7%B2%E5%88%9B%E5%BB%BA%22%5D%20--%3E%20running%5B%22running%20%E8%BF%90%E8%A1%8C%E4%B8%AD%22%5D%0A%20%20%20%20running%20--%3E%20paused%5B%22paused%20%E6%9A%82%E5%81%9C%22%5D%0A%20%20%20%20paused%20--%3E%20running%0A%20%20%20%20running%20--%3E%20stopped%5B%22stopped%20%E5%B7%B2%E5%81%9C%E6%AD%A2%22%5D%0A%20%20%20%20stopped%20--%3E%20running%0A%20%20%20%20stopped%20--%3E%20removed%5B%22deleted%20%E5%B7%B2%E5%88%A0%E9%99%A4%22%5D%0A"></div><ul><li><strong>created</strong>：分配了网络、存储、namespace，但进程还没启动</li><li><strong>running</strong>：进程正在执行</li><li><strong>paused</strong>：进程被冻结（SIGSTOP），内存保留，CPU 不再分配</li><li><strong>stopped</strong>：进程退出，文件系统和网络配置还在，可以重新启动</li><li><strong>deleted</strong>：彻底清理，可写层没了，分配的资源回收</li></ul><p>排查容器反复重启时，先判断是在 running 和 stopped 之间跳（启动命令马上退出），还是卡在 created 起不来（资源分配失败）——方向完全不同。</p><h2 id="什么适合放容器" tabindex="-1">什么适合放容器 <a class="header-anchor" href="#什么适合放容器" aria-label="Permalink to &quot;什么适合放容器&quot;">​</a></h2><p>容器擅长的是无状态或状态可以外挂的服务。Web 应用、API 网关、消息消费者、定时任务、CI 构建——这些服务本身不存数据，数据在数据库、对象存储、消息队列里。更新时起新容器、停旧容器，数据不受影响。</p><p>不适合的是强依赖特定内核版本、特定硬件、或有状态但不方便外挂的场景。需要加载内核模块的安全工具、直接操作裸盘的存储系统、绑定特定网卡硬件的网络设备——不是技术上完全做不到，而是强绑宿主机的做法和容器&quot;随处运行&quot;的出发点矛盾。</p><p>数据库可以放容器里跑，但持久化和性能要单独处理：数据目录必须放 volume 或 bind mount，网络模式可能需要 host 减少 NAT 开销，资源限制要对数据库的内存使用模式有预期。MySQL 放进容器不是不行，前提是知道容器重启后数据在哪、宿主机挂了怎么迁移、连接数怎么跟容器 IP 对应。</p><h2 id="运维视角里的边界" tabindex="-1">运维视角里的边界 <a class="header-anchor" href="#运维视角里的边界" aria-label="Permalink to &quot;运维视角里的边界&quot;">​</a></h2><p>Docker 落地后，&quot;容器外面&quot;的东西往往比&quot;容器里面&quot;更容易出问题：</p><table tabindex="0"><thead><tr><th>方向</th><th>需要确认的点</th></tr></thead><tbody><tr><td>镜像</td><td>基础镜像来源、版本标签、漏洞扫描、构建记录</td></tr><tr><td>配置</td><td>环境变量、配置文件挂载、敏感信息来源</td></tr><tr><td>网络</td><td>端口映射、容器网段、防火墙、服务发现</td></tr><tr><td>存储</td><td>volume、bind mount、备份路径、权限</td></tr><tr><td>日志</td><td>标准输出、日志驱动、采集路径、保留周期</td></tr><tr><td>资源</td><td>CPU、内存、进程数、文件句柄限制</td></tr><tr><td>安全</td><td>root 用户、特权容器、宿主机目录挂载</td></tr></tbody></table><p>容器让应用交付更标准，但宿主机仍然要管。磁盘满、镜像堆积、日志无限增长、容器没有资源限制、Docker socket 挂进容器——都是常见问题，解决点在宿主机上，不在容器里。</p>',36)])])}const B=e(d,[["render",n]]);export{u as __pageData,B as default};
